@if (Products is null || !Products.Any())
{
    <div class="text-center py-5 text-muted">
        <h4>No products found</h4>
        <p>Try adjusting your filters.</p>
    </div>
}
else
{
    <div class="row row-cols-1 row-cols-md-2 row-cols-lg-3 g-4">
        @foreach (var product in Products)
        {
            <div class="col">
                <ProductCard Product="product"
                             OnProductSelected="OnProductSelected"
                             OnAddToCart="OnAddToCart" />
            </div>
        }
    </div>
}

@code {
    [Parameter, EditorRequired]
    public List<Product> Products { get; set; } = [];

    [Parameter]
    public EventCallback<Product> OnProductSelected { get; set; }

    [Parameter]
    public EventCallback<Product> OnAddToCart { get; set; }
}

@if (TotalPages > 1)
{
    <nav aria-label="Product pagination" class="mt-4">
        <ul class="pagination justify-content-center">
            <li class="page-item @(Page <= 1 ? "disabled" : "")">
                <button class="page-link" disabled="@(Page <= 1)" @onclick="@(() => GoToPage(Page - 1))">Previous</button>
            </li>

            @foreach (var p in GetPageNumbers())
            {
                <li class="page-item @(p == Page ? "active" : "")">
                    <button class="page-link" @onclick="@(() => GoToPage(p))">@p</button>
                </li>
            }

            <li class="page-item @(Page >= TotalPages ? "disabled" : "")">
                <button class="page-link" disabled="@(Page >= TotalPages)" @onclick="@(() => GoToPage(Page + 1))">Next</button>
            </li>
        </ul>
    </nav>
}

@code {
    [Parameter]
    public int Page { get; set; } = 1;

    [Parameter]
    public int TotalPages { get; set; }

    [Parameter]
    public EventCallback<int> OnPageChanged { get; set; }

    private async Task GoToPage(int page)
    {
        if (page >= 1 && page <= TotalPages && page != Page)
        {
            await OnPageChanged.InvokeAsync(page);
        }
    }

    private IEnumerable<int> GetPageNumbers()
    {
        // Show up to 7 page buttons with ellipsis-like windowing
        const int maxVisible = 7;

        if (TotalPages <= maxVisible)
        {
            return Enumerable.Range(1, TotalPages);
        }

        var start = Math.Max(1, Page - maxVisible / 2);
        var end = Math.Min(TotalPages, start + maxVisible - 1);
        if (end - start + 1 < maxVisible)
        {
            start = Math.Max(1, end - maxVisible + 1);
        }
        return Enumerable.Range(start, end - start + 1);
    }
}

