@page "/catalog"
@rendermode InteractiveServer
@using sv_163f0ca2f0b24bd0ac33fb2b02620794.Components.Catalog
@inject IProductService ProductService

<PageTitle>Product Catalog</PageTitle>

<h2 class="mb-4">Product Catalog</h2>

@if (_error is not null)
{
    <div class="alert alert-danger" role="alert">
        <strong>Error:</strong> @_error
        <button class="btn btn-sm btn-outline-danger ms-3" @onclick="RetryLoad">Retry</button>
    </div>
}
else
{
    <div class="row">
        <div class="col-lg-3 mb-4">
            @if (_categories is null)
            {
                <div class="text-center py-3">
                    <div class="spinner-border spinner-border-sm" role="status"></div>
                    <span class="ms-2">Loading filters…</span>
                </div>
            }
            else
            {
                <CatalogFilters Categories="_categories"
                                OnFiltersApplied="HandleFiltersApplied" />
            }
        </div>

        <div class="col-lg-9">
            <CatalogToolbar SortBy="@_sortBy"
                            TotalCount="_totalCount"
                            Page="_page"
                            PageSize="PageSize"
                            OnSortChanged="HandleSortChanged" />

            @if (_loading)
            {
                <div class="text-center py-5">
                    <div class="spinner-border" role="status">
                        <span class="visually-hidden">Loading products…</span>
                    </div>
                </div>
            }
            else
            {
                <ProductGrid Products="_products"
                             OnProductSelected="HandleProductSelected"
                             OnAddToCart="HandleAddToCart" />

                <CatalogPagination Page="_page"
                                   TotalPages="_totalPages"
                                   OnPageChanged="HandlePageChanged" />
            }
        </div>
    </div>
}

@code {
    private const int PageSize = 12;

    private List<string>? _categories;
    private List<Product> _products = [];
    private ProductFilter _filter = new(null, null, null, false);
    private string _sortBy = "price_asc";
    private int _page = 1;
    private int _totalCount;
    private int _totalPages;
    private bool _loading = true;
    private string? _error;

    [Parameter]
    public EventCallback<Product> OnProductSelected { get; set; }

    [Parameter]
    public EventCallback<Product> OnAddToCart { get; set; }

    protected override async Task OnInitializedAsync()
    {
        await LoadDataAsync();
    }

    private async Task LoadDataAsync()
    {
        try
        {
            _loading = true;
            _error = null;

            var categoriesTask = _categories is null
                ? ProductService.GetCategoriesAsync()
                : Task.FromResult(_categories);

            var searchTask = ProductService.SearchAsync(_filter, _sortBy, _page, PageSize);

            await Task.WhenAll(categoriesTask, searchTask);

            _categories = await categoriesTask;
            var result = await searchTask;

            _products = result.Items;
            _totalCount = result.TotalCount;
            _totalPages = (int)Math.Ceiling((double)result.TotalCount / PageSize);
        }
        catch (Exception ex)
        {
            _error = ex.Message;
        }
        finally
        {
            _loading = false;
        }
    }

    private async Task HandleFiltersApplied(ProductFilter filter)
    {
        _filter = filter;
        _page = 1;
        await LoadDataAsync();
    }

    private async Task HandleSortChanged(string sortBy)
    {
        _sortBy = sortBy;
        _page = 1;
        await LoadDataAsync();
    }

    private async Task HandlePageChanged(int page)
    {
        _page = page;
        await LoadDataAsync();
    }

    private async Task HandleProductSelected(Product product)
    {
        await OnProductSelected.InvokeAsync(product);
    }

    private async Task HandleAddToCart(Product product)
    {
        await OnAddToCart.InvokeAsync(product);
    }

    private async Task RetryLoad()
    {
        await LoadDataAsync();
    }
}

